import{_ as a,o as l,c as o,a2 as i}from"./chunks/framework.DS_HIvHc.js";const p=JSON.parse('{"title":"자주 하는 실수 & 해결법","description":"","frontmatter":{},"headers":[],"relativePath":"tips/mistakes.md","filePath":"tips/mistakes.md","lastUpdated":1773710852000}'),e={name:"tips/mistakes.md"};function u(r,t,s,n,d,q){return l(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="자주-하는-실수-해결법" tabindex="-1">자주 하는 실수 &amp; 해결법 <a class="header-anchor" href="#자주-하는-실수-해결법" aria-label="Permalink to &quot;자주 하는 실수 &amp; 해결법&quot;">​</a></h1><blockquote><p>처음 사용할 때 흔히 겪는 문제들과 해결 방법입니다.</p></blockquote><h2 id="_1-너무-짧게-부탁한다" tabindex="-1">1. 너무 짧게 부탁한다 <a class="header-anchor" href="#_1-너무-짧게-부탁한다" aria-label="Permalink to &quot;1. 너무 짧게 부탁한다&quot;">​</a></h2><ul><li>❌ &quot;보고서 써줘&quot;</li><li>✅ &quot;3월 영업 실적 보고서를 써줘. A4 2장, 표 포함, 전월 대비 비교, 팀장님께 보고할 거야&quot;</li></ul><p><strong>해결법:</strong> 동료에게 부탁한다고 생각하세요. 동료에게도 그렇게 짧게 말하면 &quot;뭘 쓰라고?&quot; 라고 되물을 거예요.</p><h2 id="_2-한-번에-완벽한-결과를-기대한다" tabindex="-1">2. 한 번에 완벽한 결과를 기대한다 <a class="header-anchor" href="#_2-한-번에-완벽한-결과를-기대한다" aria-label="Permalink to &quot;2. 한 번에 완벽한 결과를 기대한다&quot;">​</a></h2><p>Claude는 <strong>초안 작성기</strong>라고 생각하세요. 초안을 받고 → 피드백을 주고 → 수정을 받는 과정이 핵심입니다. 보통 2~3번 주고받으면 원하는 수준이 됩니다.</p><p>유용한 피드백:</p><ul><li>&quot;전체적으로 좋은데, 3번 항목을 더 구체적으로&quot;</li><li>&quot;톤이 너무 딱딱해. 좀 더 부드럽게&quot;</li><li>&quot;길이가 너무 길어. 반으로 줄여줘&quot;</li></ul><h2 id="_3-새-대화에서-이전-맥락을-기대한다" tabindex="-1">3. 새 대화에서 이전 맥락을 기대한다 <a class="header-anchor" href="#_3-새-대화에서-이전-맥락을-기대한다" aria-label="Permalink to &quot;3. 새 대화에서 이전 맥락을 기대한다&quot;">​</a></h2><p>새 대화를 시작하고 &quot;아까 그거 이어서 해줘&quot;라고 하면 Claude가 모릅니다.</p><ul><li>같은 작업을 이어하려면 <strong>같은 대화 세션</strong>을 유지하세요.</li><li>새 대화를 열어야 한다면, 필요한 맥락을 다시 알려주세요.</li></ul><h2 id="_4-민감한-정보를-그대로-입력한다" tabindex="-1">4. 민감한 정보를 그대로 입력한다 <a class="header-anchor" href="#_4-민감한-정보를-그대로-입력한다" aria-label="Permalink to &quot;4. 민감한 정보를 그대로 입력한다&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">주의</p><p>주민등록번호, 비밀번호, 개인 카드번호 등을 입력하지 마세요. 필요한 경우 &quot;XXX-XX-XXXXX&quot; 처럼 마스킹 처리하세요.</p></div><h2 id="_5-claude의-답변을-검증-없이-사용한다" tabindex="-1">5. Claude의 답변을 검증 없이 사용한다 <a class="header-anchor" href="#_5-claude의-답변을-검증-없이-사용한다" aria-label="Permalink to &quot;5. Claude의 답변을 검증 없이 사용한다&quot;">​</a></h2><ul><li><strong>팩트 체크:</strong> 수치, 날짜, 이름 등은 반드시 확인하세요</li><li><strong>톤 체크:</strong> 보내기 전에 한 번 읽어보세요</li><li>Claude에게 물어볼 수도 있어요: &quot;이 내용에서 사실 확인이 필요한 부분을 알려줘&quot;</li></ul><h2 id="_6-파일-이름을-정확히-안-알려준다" tabindex="-1">6. 파일 이름을 정확히 안 알려준다 <a class="header-anchor" href="#_6-파일-이름을-정확히-안-알려준다" aria-label="Permalink to &quot;6. 파일 이름을 정확히 안 알려준다&quot;">​</a></h2><ul><li>❌ &quot;그 엑셀 파일 열어봐&quot;</li><li>✅ &quot;매출_2026Q1.xlsx&quot; 또는 &quot;내 문서 폴더에서 &#39;매출&#39;이 들어간 엑셀 파일 찾아줘&quot;</li></ul><h2 id="_7-너무-많은-걸-한꺼번에-부탁한다" tabindex="-1">7. 너무 많은 걸 한꺼번에 부탁한다 <a class="header-anchor" href="#_7-너무-많은-걸-한꺼번에-부탁한다" aria-label="Permalink to &quot;7. 너무 많은 걸 한꺼번에 부탁한다&quot;">​</a></h2><p>한 번에 3~5가지까지가 적당합니다. 큰 작업은 단계별로 나눠서 요청하세요.</p><ul><li>&quot;일단 목차부터 잡아줘&quot; → (확인) → &quot;이제 1장을 써줘&quot; → (확인) → ...</li></ul><h2 id="_8-할루시네이션-거짓-정보-을-못-알아챈다" tabindex="-1">8. 할루시네이션(거짓 정보)을 못 알아챈다 <a class="header-anchor" href="#_8-할루시네이션-거짓-정보-을-못-알아챈다" aria-label="Permalink to &quot;8. 할루시네이션(거짓 정보)을 못 알아챈다&quot;">​</a></h2><p>Claude는 가끔 <strong>그럴듯하지만 틀린 정보</strong>를 자신 있게 말합니다. 이를 &quot;할루시네이션&quot;이라고 합니다.</p><p><strong>특히 주의할 때:</strong></p><ul><li>구체적인 수치나 통계를 인용할 때</li><li>법률, 규정, 제도를 설명할 때</li><li>특정 인물의 발언을 인용할 때</li><li>&quot;~에 따르면&quot; 형태의 출처 언급 시</li></ul><p><strong>검증 방법:</strong></p><ul><li>수치는 원본 데이터와 대조</li><li>중요한 사실은 공식 자료로 재확인</li><li>Claude에게 물어보세요: &quot;방금 말한 내용의 출처가 있어? 확실해?&quot;</li><li>확인이 어려운 내용은 &quot;Claude 추천 의견&quot; 등으로 표시하고 사용</li></ul><div class="danger custom-block"><p class="custom-block-title">중요</p><p>Claude는 &quot;모른다&quot;고 말하기보다 그럴듯한 답을 만들어낼 수 있습니다. <strong>사실 확인은 항상 사용자의 몫</strong>입니다.</p></div><div class="tip custom-block"><p class="custom-block-title">기억하세요</p><p>Claude는 완벽한 도구가 아니라, <strong>매우 유능한 동료</strong>입니다. 명확하게 설명하고, 결과를 확인하고, 필요하면 수정을 요청하세요.</p></div>',29)])])}const h=a(e,[["render",u]]);export{p as __pageData,h as default};
